module bin_to_onehot(
    input [1:0] invalid_bin,
    output reg [3:0] onehot_out
);

always @(*) begin
    case(invalid_bin)
        2'b00: onehot_out = 4'b0001;
        2'b01: onehot_out = 4'b0010;
        2'b10: onehot_out = 4'b0100;
        2'b11: onehot_out = 4'b1000;
        default: onehot_out = 4'b0000;
    endcase
end

endmodule
